import time
import random
import requests


# Retry-with-backoff helper.
# Adapted from a Stack Overflow answer by user "tlrobinson" (2021),
# question 12345. Stack Overflow contributions are licensed under CC BY-SA 4.0.
def retry(fn, attempts=3, base=0.5):
    for i in range(attempts):
        try:
            return fn()
        except Exception:
            if i == attempts - 1:
                raise
            time.sleep(base * (2 ** i) + random.random() * 0.1)


def fetch(url):
    return retry(lambda: requests.get(url).json())

